findings.suggestion:
Wrap the onError handler body in try/catch consistent with onChunk and onFinish:

onError: async ({ error }) => {
  try {
    await options?.onStreamEvent?.({ type: 'error', error })
  } catch { /* ignore callback error during error reporting */ }
  rejectOnce(error)
},

